//요일 불러오기
scwin.f_getDay = function (){	

	var currDate = ica_printDt.getValue();
	//alert(currDate);
	var date = new Date(currDate.substring(0,4),currDate.substring(4,6)-1,currDate.substring(6,8));
	var currDay = date.getDay();
	//alert(currDay);
	switch(currDay) {
	  	case 1:
	  		scwin.day = "월요일";
	  		break;
	  	case 2:
	  		scwin.day = "화요일";
	  		break;
	  	case 3:
	  		scwin.day = "수요일";
	  		break;
	  	case 4:
	  		scwin.day = "목요일";
	  		break;
	  	case 5:
	  		scwin.day = "금요일";
	  		break;
	  	case 6:
	  		scwin.day = "토요일";
	  		break;
	  	case 0:
	  		scwin.day = "일요일";
	  		break;
	}	
	//alert(day);
};

